@page "/"
@using ShipmentTracker.Client.Services
@using ShipmentTracker.Client.Models
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Home</PageTitle>

<div class="container">
    <div class="text-center my-5">
        <h1>Shipment Tracker</h1>
        <p class="lead">Track your shipments in real-time</p>
    </div>

    <div class="row justify-content-center">
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Track a Shipment</h5>
                    <div class="input-group">
                        <input type="text" class="form-control" placeholder="Enter tracking number..."
                               @bind="trackingNumber" @bind:event="oninput"
                               @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
                    </div>
                    @if (!string.IsNullOrEmpty(errorMessage))
                    {
                        <div class="alert alert-warning mt-3">@errorMessage</div>
                    }
                </div>
            </div>
        </div>
    </div>

    @if (trackedShipment != null)
    {
        <div class="row justify-content-center mt-4">
            <div class="col-md-8">
                <div class="card">
                    <div class="card-header">
                        <strong>@trackedShipment.TrackingNumber</strong>
                    </div>
                    <div class="card-body">
                        <dl class="row mb-0">
                            <dt class="col-sm-4">Status</dt>
                            <dd class="col-sm-8"><span class="badge bg-info">@trackedShipment.Status</span></dd>
                            <dt class="col-sm-4">Origin</dt>
                            <dd class="col-sm-8">@trackedShipment.Origin</dd>
                            <dt class="col-sm-4">Destination</dt>
                            <dd class="col-sm-8">@trackedShipment.Destination</dd>
                            <dt class="col-sm-4">Description</dt>
                            <dd class="col-sm-8">@trackedShipment.Description</dd>
                            <dt class="col-sm-4">Estimated Delivery</dt>
                            <dd class="col-sm-8">@(trackedShipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "N/A")</dd>
                        </dl>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingNumber = string.Empty;
    private string? errorMessage;
    private ShipmentDto? trackedShipment;

    private async Task TrackShipment()
    {
        errorMessage = null;
        trackedShipment = null;

        if (string.IsNullOrWhiteSpace(trackingNumber))
        {
            errorMessage = "Please enter a tracking number.";
            return;
        }

        trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        if (trackedShipment == null)
        {
            errorMessage = "Shipment not found. Please check the tracking number.";
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>All Shipments - Dispatcher</PageTitle>

<h2>All Shipments</h2>

@if (isLoading)
{
    <p>Loading shipments...</p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>

    @if (showCreate)
    {
        <div class="card mb-4">
            <div class="card-header">Create New Shipment</div>
            <div class="card-body">
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Tracking Number" @bind="newShipment.TrackingNumber" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-2">
                        <input class="form-control" placeholder="Description" @bind="newShipment.Description" />
                    </div>
                    <div class="col-md-1">
                        <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    </div>
                </div>
            </div>
        </div>
    }

    @if (shipments.Count == 0)
    {
        <p>No shipments found.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Tracking #</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Customer</th>
                        <th>Created</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in shipments)
                    {
                        <tr>
                            <td>@shipment.TrackingNumber</td>
                            <td>@shipment.Origin</td>
                            <td>@shipment.Destination</td>
                            <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                            <td>@shipment.CustomerEmail</td>
                            <td>@shipment.CreatedDate.ToString("MMM dd, yyyy")</td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "N/A")</td>
                            <td>
                                <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                        @onchange="(e) => UpdateStatus(shipment.Id, e.Value?.ToString())">
                                    <option value="">Change status...</option>
                                    <option value="Pending">Pending</option>
                                    <option value="PickedUp">Picked Up</option>
                                    <option value="InTransit">In Transit</option>
                                    <option value="OutForDelivery">Out For Delivery</option>
                                    <option value="Delivered">Delivered</option>
                                    <option value="Cancelled">Cancelled</option>
                                </select>
